import{promises as e}from"node:fs";import{dirname as i}from"node:path";export async function ensureDir(r){await e.mkdir(r,{recursive:!0})}export async function readJson(r){try{const t=await e.readFile(r,"utf8");return JSON.parse(t)}catch(t){if(t?.code==="ENOENT")return null;throw new Error(`Failed to read ${r}: ${t?.message??t}`)}}export async function writeJson(r,t){await ensureDir(i(r)),await e.writeFile(r,JSON.stringify(t,null,2),"utf8")}export async function writeText(r,t){await ensureDir(i(r)),await e.writeFile(r,t,"utf8")}
